// Formatea adultos + bebés menores de 2 años
const fmtPax = r => {
  const a = r.pax||0, b = r.bebes||0;
  const parts = [];
  if(a>0) parts.push(`${a} adulto${a!==1?"s":""}`);
  if(b>0) parts.push(`${b} bebé${b!==1?"s":""} <2a`);
  return parts.length ? parts.join(" · ") : "—";
};

/* ── Estado de pago real — fuente de verdad única ── */
// status: "pendiente" | "señado" | "parcial" | "pagado"
// "señado": hay exactamente 1 pago registrado y es la seña inicial.
// Ya NO depende de r.senia — toda la lógica viene de paidAmount y payments[].
const getPaymentStatus = r => {
  const pmts    = r.payments || [];
  const paid    = r.paidAmount !== undefined ? r.paidAmount : pmts.reduce((s,p)=>s+p.amount, 0);
  const total   = r.amt || 0;
  const pending = Math.max(0, total - paid);
  let status;
  if      (paid <= 0)    status = "pendiente";
  else if (paid >= total) status = "pagado";
  else if (pmts.length === 1 && (pmts[0]?.method||"").toLowerCase().includes("seña")) status = "señado";
  else                   status = "parcial";
  return { status, paid, pending, total };
};
// ── Helpers de comisión ─────────────────────────────────────────────────
// Calcula la ganancia de Hagrids según el modo configurado en la reserva.
//   "porcentaje"    → ganancia = amt × comision%
//   "valorAgregado" → ganancia = amt − precioOwner  (markup sobre precio base)
const getComision = r => {
  if(r.comisionMode === "valorAgregado" && (r.precioOwner ?? "") !== "") {
    return Math.max(0, (r.amt||0) - (+(r.precioOwner)||0));
  }
  return Math.round((r.amt||0) * (r.comision||0) / 100);
};
// Ingresos netos que le corresponden al propietario
const getOwnerIncome = r => {
  if(r.comisionMode === "valorAgregado" && (r.precioOwner ?? "") !== "") {
    return +(r.precioOwner) || 0;
  }
  return (r.amt||0) - getComision(r);
};
// Porcentaje efectivo de comisión (1 decimal, para mostrar en UI)
const getComisionPct = r => {
  if(!r.amt || +r.amt <= 0) return 0;
  return Math.round(getComision(r) / r.amt * 1000) / 10;
};

