  /* ══════════════════════════════════════════════════════
     BLOQUE 8 — HELPER DE PDF
     Clona el elemento fuera del modal, captura limpio,
     escala para llenar la página A4 completa.
  ══════════════════════════════════════════════════════ */
  const descargarPDF = async (elementId, filename, captureW = 600) => {
    const el = document.getElementById(elementId);
    if(!el){ console.warn("descargarPDF: elemento no encontrado:", elementId); return; }

    const CAPTURE_W = captureW;

    // Clonar fuera de cualquier modal para evitar clipping
    const clone = el.cloneNode(true);
    Object.assign(clone.style, {
      position:   "fixed",
      top:        "-9999px",
      left:       "0px",
      width:      CAPTURE_W + "px",
      maxWidth:   "none",
      height:     "auto",
      maxHeight:  "none",
      overflow:   "visible",
      zIndex:     "-1",
      background: "#ffffff",
    });
    clone.querySelectorAll("*").forEach(n => {
      n.style.overflow  = "visible";
      n.style.overflowY = "visible";
      n.style.overflowX = "visible";
      n.style.maxHeight = "none";
      n.style.maxWidth  = "100%";
    });
    document.body.appendChild(clone);

    await new Promise(r => requestAnimationFrame(() => requestAnimationFrame(r)));
    await new Promise(r => setTimeout(r, 180));

    const fullH = clone.scrollHeight + 32;
    clone.style.height = fullH + "px";

    let canvas;
    try {
      canvas = await html2canvas(clone, {
        scale:           2,
        useCORS:         true,
        allowTaint:      true,
        logging:         false,
        width:           CAPTURE_W,
        height:          fullH,
        windowWidth:     Math.max(1200, CAPTURE_W),
        windowHeight:    fullH,
        scrollX:         0,
        scrollY:         -clone.getBoundingClientRect().top,
        backgroundColor: "#ffffff",
      });
    } finally {
      document.body.removeChild(clone);
    }

    if(!canvas) return;

        const pdf   = new jsPDF({ unit:"mm", format:"a4", orientation:"portrait" });
    const pageW = pdf.internal.pageSize.getWidth();
    const pageH = pdf.internal.pageSize.getHeight();
    const imgH  = (canvas.height / canvas.width) * pageW;

    if(imgH <= pageH) {
      const yPos = (pageH - imgH) / 2;
      pdf.addImage(canvas.toDataURL("image/jpeg", 0.97), "JPEG", 0, yPos, pageW, imgH);
    } else {
      const totalPages = Math.ceil(imgH / pageH);
      for(let i = 0; i < totalPages; i++) {
        if(i > 0) pdf.addPage();
        pdf.addImage(canvas.toDataURL("image/jpeg", 0.97), "JPEG", 0, -i * pageH, pageW, imgH);
      }
    }

    pdf.save(filename.endsWith(".pdf") ? filename : filename + ".pdf");
  };

